import{c as t,Q as o,j as a,m as r}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse(`{"title":"Ben's Bites — 2026-04-07","description":"","frontmatter":{"title":"Ben's Bites — 2026-04-07","date":"2026-04-07T00:00:00.000Z","source":"Ben's Bites","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-04/2026-04-07-bens-bites.md","filePath":"research/ai-news/2026-04/2026-04-07-bens-bites.md","lastUpdated":1779796674000}`),n={name:"research/ai-news/2026-04/2026-04-07-bens-bites.md"};function s(u,e,l,i,p,h){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="🍔-ben-s-bites-—-2026-04-07" tabindex="-1">🍔 Ben&#39;s Bites — 2026-04-07 <a class="header-anchor" href="#🍔-ben-s-bites-—-2026-04-07" aria-label="Permalink to &quot;🍔 Ben&#39;s Bites — 2026-04-07&quot;">​</a></h1><blockquote><p>Ben Tossell 的 AI 日報，工具圈消息源 來源：<a href="https://www.bensbites.com/feed" target="_blank" rel="noreferrer">Ben&#39;s Bites</a></p></blockquote><hr><h2 id="no-claude-for-claws" tabindex="-1"><a href="https://www.bensbites.com/p/no-claude-for-claws" target="_blank" rel="noreferrer">No Claude for Claws</a> <a class="header-anchor" href="#no-claude-for-claws" aria-label="Permalink to &quot;[No Claude for Claws](https://www.bensbites.com/p/no-claude-for-claws)&quot;">​</a></h2><p><em>🍔 Ben&#39;s Bites | 2026-04-07</em></p><p><a href="https://x.com/bcherny/status/2040206440556826908" target="_blank" rel="noreferrer">Anthropic cut off Claude subscription-funded usage in third-party tools</a> like OpenClaw. You can still use Claude models through OpenClaw, but it now requires separate pay-as-you-go billing or your own API key — your Claude Code subscription no longer works. Anthropic offered a one-time credit equal to one month’s subscription to soften the blow. The move comes as agentic usage through third-party harnesses was eating massive compute, and Anthropic is clearly steering users toward its own tools: Dispatch, scheduled tasks, projects, and computer use, which directly overlap with what OpenClaw offers.</p><p>But OpenClaw founder, Peter, is a (good-kind of) maniac who’s trying to get gpt5.4 working like opus in the tool (since OpenAI acquired him).</p><p>Unfortunately it’s just left the whole community confused as to where and when they can use their Claude Code subscriptions outside of the cc harness itself. Myself included.</p><p>There’s <a href="https://x.com/karpathy/status/2039805659525644595" target="_blank" rel="noreferrer">a new take on knowledge bases</a> that I think is very interesting by Andrej Karpathy. Memory and file organisation for retrieval got a big focus with the OpenClaw hype but this approach groups things topically and then enhances with summaries, backlinks and wikis.</p><p>Related, Farza built <a href="https://x.com/FarzaTV/status/2040563939797504467" target="_blank" rel="noreferrer">Farzapedia</a>, a personal Wikipedia generated from 2,500 diary entries, notes and messages. Built for his agents to crawl whenever needed. <a href="https://x.com/karpathy/status/2040572272944324650" target="_blank" rel="noreferrer">Karpathy’s take on Farzapedia</a></p><p><a href="https://x.com/johncoogan/status/2039756493621542915" target="_blank" rel="noreferrer">OpenAI acquired TBPN</a> -- good pod to get a peek into the heads of <a href="https://x.com/DialecticPod/status/1990452333625446822" target="_blank" rel="noreferrer">the hosts</a>. A lot of people on X are trying to sound smart with ‘this is why they acquired them’ but I’m more in the Ben Thompson camp… I don’t really know why either party needs each other here? TBPN is loved, growing, and making a small fortune with their (also loved!) ad business. Why does OpenAI need them? Other than the fact that they don’t like traditional media and could use TBPN as their main channel to people that matter.</p><p>Ben’s Bites is brought to you by <a href="https://reevo.ai/" target="_blank" rel="noreferrer">Reevo</a></p><p>The best sellers aren’t the ones with the most sophisticated tech stack. They’re the ones who spend the most time selling. <a href="https://reevo.ai/" target="_blank" rel="noreferrer">Reevo</a> is the AI-native revenue intelligence system and CRM that every team deserves. One Platform. From prospect to close in a single tab. Go Stackless. <a href="http://reevo.ai/" target="_blank" rel="noreferrer">Reevo.ai</a></p><p>Headlines</p><p><a href="https://blog.google/innovation-and-ai/technology/developers-tools/gemma-4/" target="_blank" rel="noreferrer">Google released Gemma 4</a>. 4 new open-weights models - two for powerful laptops and desktops (26B MoE and 31B dense), and two tiny ones for mobile phones (2B &amp; 4B). Relevant for companies that want to fine-tune them, not for direct use.</p><p><a href="https://cursor.com/blog/cursor-3" target="_blank" rel="noreferrer">Cursor-3 adds a new standalone window for running agents</a>. Has some neat additions for local to cloud handoff, working across different projects.</p><p><a href="https://x.com/AnthropicAI/status/2041275563466502560" target="_blank" rel="noreferrer">Anthropic’s run-rate revenue hit $30B</a>, up from $9B at the end of 2025. Lenny’s podcast with Anthropic’s head of growth is <a href="http://youtube.com/watch?v=k-H4nsOTuxU&amp;feature=youtu.be" target="_blank" rel="noreferrer">worth a listen</a> — they added $6B ARR in February alone.</p><p><a href="https://fandf.co/4s3g1Fw" target="_blank" rel="noreferrer">Adapt is your company’s AI computer.</a> It connects to your tools and team, autonomously learns your business, and gets smarter with every task. Pull live data, run scheduled workflows, and deploy internal apps everyone can use, all from Slack.*</p><p>My feed</p><p><a href="https://salmex.io/" target="_blank" rel="noreferrer">Salmex I/O</a> — Won&#39;t forget you. Gets things done. Answers to no one. And is actually safe! What a local AI agent should be.*</p><p><a href="https://sunilpai.dev/posts/developer-relations/" target="_blank" rel="noreferrer">What could “devrel” mean</a> in a world with slot machines spitting out code and opinions?</p><p><a href="https://x.com/ctatedev/status/2041176865092563122" target="_blank" rel="noreferrer">agent-browser by Vercel</a> can now also work as a browser agent with a chat-bar on the side.</p><p>Turning <a href="https://x.com/arlanr/status/2041215978957389908" target="_blank" rel="noreferrer">any documentation website into a filesystem</a> for agents to navigate with tree, grep, cat, etc.</p><p>The CEO of Brex claims he is <a href="https://www.youtube.com/watch?v=9ZbbxSgrjhw" target="_blank" rel="noreferrer">running the $5B+ company</a> with OpenClaw.</p><p>Growth ideas that helped Michelle scale Warp to <a href="https://x.com/michlimlim/status/2039777473123283018" target="_blank" rel="noreferrer">500k+ weekly active developers</a>.</p><p><a href="https://x.com/tbpn/status/2041286830214259069" target="_blank" rel="noreferrer">The era of web apps is over</a> - Bret Taylor</p><p><a href="https://reducto.ai/blog/reducto-deep-extract-agent" target="_blank" rel="noreferrer">Deep Extract</a> adds an agent in the loop for extracting data out of complex documents that verifies and corrects itself.</p><p>Samuel is building skills (<a href="https://x.com/samuel_spitz/status/2041198900791714278" target="_blank" rel="noreferrer">like this AI SDR one</a>) for the Replit Agent and sharing them on X. Cool way to market agents to non-technical users.</p><p>Simon is the most up-to-date person on LLMs. He was on Lenny’s pod to talk about the <a href="https://www.youtube.com/watch?v=wc8FBhQtdsA" target="_blank" rel="noreferrer">changes in AI coding</a> over the last few months.</p><p>Intercom is making its agent <a href="https://fin.ai/api-platform" target="_blank" rel="noreferrer">Fin available via API</a> for companies with contracts starting at $250k per year. (<a href="https://x.com/eoghan/status/2040115778251612232" target="_blank" rel="noreferrer">read more</a>)</p><p>Loophole translates your natural language <a href="https://x.com/brendanh0gan/status/2040553395329675375" target="_blank" rel="noreferrer">moral beliefs into codified laws</a> and then tries to break them.</p><p>Ex-OpenAI board member (left after the Sam Altman firing fiasco) argues for <a href="https://helentoner.substack.com/p/the-term-agi-is-almost-useless-at" target="_blank" rel="noreferrer">retiring the term AGI</a> in favour of specific milestones.</p><p>You can now use your agent to <a href="https://x.com/danshipper/status/2041207904280170629" target="_blank" rel="noreferrer">apply for a job</a> at Every.</p><p><a href="https://x.com/kevingu/status/2039843234760073341" target="_blank" rel="noreferrer">Autoagent</a> - An agent to help optimise agents.</p><p><a href="https://www.youtube.com/watch?v=8wQBvT6L8Xk" target="_blank" rel="noreferrer">Planning is dead</a></p><p>A YC partner one-shotted a tool to <a href="https://x.com/t_blom/status/2040994452962177256" target="_blank" rel="noreferrer">manage his inbox with voice</a>. Another YC company <a href="http://stampmail.ai/" target="_blank" rel="noreferrer">launched an AI secretary</a> that manages your email like you.</p><p>Afters</p><p>@browserbase CLI &quot;,&quot;username&quot;:&quot;shreypandya&quot;,&quot;name&quot;:&quot;Shrey Pandya&quot;,&quot;profile_image_url&quot;:&quot;<a href="https://pbs.substack.com/profile_images/1634935701039992834/Wa4dk57c_normal.jpg%22,%22date%22:%222026-04-03T00:02:40.000Z%22,%22photos%22:%5B%7B%22img_url%22:%22https://substackcdn.com/image/upload/w_1028,c_limit,q_auto:best/l_twitter_play_button_rvaygk,w_88/jyfiethtxqoaipcg5anf%22,%22link_url%22:%22https://t.co/sIEhWBCPJW%22%7D%5D,%22quoted_tweet%22:%7B%7D,%22reply_count%22:25,%22retweet_count%22:43,%22like_count%22:575,%22impression_count%22:54397,%22expanded_url%22:null,%22video_url%22:%22https://video.twimg.com/amplify_video/2039855835237810176/vid/avc1/1136x720/aIMsRqvKnN7vvm47.mp4%22,%22belowTheFold%22:true%7D%22" target="_blank" rel="noreferrer">https://pbs.substack.com/profile_images/1634935701039992834/Wa4dk57c_normal.jpg&quot;,&quot;date&quot;:&quot;2026-04-03T00:02:40.000Z&quot;,&quot;photos&quot;:[{&quot;img_url&quot;:&quot;https://substackcdn.com/image/upload/w_1028,c_limit,q_auto:best/l_twitter_play_button_rvaygk,w_88/jyfiethtxqoaipcg5anf&quot;,&quot;link_url&quot;:&quot;https://t.co/sIEhWBCPJW&quot;}],&quot;quoted_tweet&quot;:{},&quot;reply_count&quot;:25,&quot;retweet_count&quot;:43,&quot;like_count&quot;:575,&quot;impression_count&quot;:54397,&quot;expanded_url&quot;:null,&quot;video_url&quot;:&quot;https://video.twimg.com/amplify_video/2039855835237810176/vid/avc1/1136x720/aIMsRqvKnN7vvm47.mp4&quot;,&quot;belowTheFold&quot;:true}&quot;</a> data-component-name=&quot;Twitter2ToDOM&quot;&gt;</p><p>@Cloudflare. I&#39;m incredibly grateful for the freedom I was given to explore ideas and to everyone on the Agents team for being the most cracked and amazing teammates.\\n\\nI&#39;m going to be starting a new company, The Agents Company (theagents.company),&quot;,&quot;username&quot;:&quot;deathbyknowledg&quot;,&quot;name&quot;:&quot;Steve James&quot;,&quot;profile_image_url&quot;:&quot;<a href="https://pbs.substack.com/profile_images/2037170906670190592/JY3YdYw1_normal.jpg%22,%22date%22:%222026-04-03T18:18:29.000Z%22,%22photos%22:%5B%5D,%22quoted_tweet%22:%7B%7D,%22reply_count%22:20,%22retweet_count%22:18,%22like_count%22:350,%22impression_count%22:101479,%22expanded_url%22:%7B%22url%22:%22https://theagents.company%22,%22title%22:%22The" target="_blank" rel="noreferrer">https://pbs.substack.com/profile_images/2037170906670190592/JY3YdYw1_normal.jpg&quot;,&quot;date&quot;:&quot;2026-04-03T18:18:29.000Z&quot;,&quot;photos&quot;:[],&quot;quoted_tweet&quot;:{},&quot;reply_count&quot;:20,&quot;retweet_count&quot;:18,&quot;like_count&quot;:350,&quot;impression_count&quot;:101479,&quot;expanded_url&quot;:{&quot;url&quot;:&quot;https://theagents.company&quot;,&quot;title&quot;:&quot;The</a> Agents Company | Personal AI Infrastructure&quot;,&quot;description&quot;:&quot;Open-source personal AI infrastructure, cognitive firewall, and products built to make agency useful without becoming slop.&quot;,&quot;domain&quot;:&quot;theagents.company&quot;,&quot;image&quot;:&quot;<a href="https://pbs.substack.com/news_img/2040131848639029248/4RmZssGE?format=jpg&amp;name=orig%22%7D,%22video_url%22:null,%22belowTheFold%22:true%7D%22" target="_blank" rel="noreferrer">https://pbs.substack.com/news_img/2040131848639029248/4RmZssGE?format=jpg&amp;name=orig&quot;},&quot;video_url&quot;:null,&quot;belowTheFold&quot;:true}&quot;</a> data-component-name=&quot;Twitter2ToDOM&quot;&gt;</p><p>@togethercompute and @FFmpeg via fluent-ffmpeg. &quot;,&quot;username&quot;:&quot;nutlope&quot;,&quot;name&quot;:&quot;Hassan&quot;,&quot;profile_image_url&quot;:&quot;<a href="https://pbs.substack.com/profile_images/1727415759859552256/9rqaxXUR_normal.jpg%22,%22date%22:%222026-04-06T17:00:45.000Z%22,%22photos%22:%5B%7B%22img_url%22:%22https://substackcdn.com/image/upload/w_1028,c_limit,q_auto:best/l_twitter_play_button_rvaygk,w_88/omup0q4qtnaxyaudbceo%22,%22link_url%22:%22https://t.co/kItRvmDB4D%22%7D%5D,%22quoted_tweet%22:%7B%7D,%22reply_count%22:47,%22retweet_count%22:132,%22like_count%22:1149,%22impression_count%22:74215,%22expanded_url%22:null,%22video_url%22:%22https://video.twimg.com/amplify_video/2041197846888611840/vid/avc1/1088x720/e_TeuAl0d5aZ-EJr.mp4%22,%22belowTheFold%22:true%7D%22" target="_blank" rel="noreferrer">https://pbs.substack.com/profile_images/1727415759859552256/9rqaxXUR_normal.jpg&quot;,&quot;date&quot;:&quot;2026-04-06T17:00:45.000Z&quot;,&quot;photos&quot;:[{&quot;img_url&quot;:&quot;https://substackcdn.com/image/upload/w_1028,c_limit,q_auto:best/l_twitter_play_button_rvaygk,w_88/omup0q4qtnaxyaudbceo&quot;,&quot;link_url&quot;:&quot;https://t.co/kItRvmDB4D&quot;}],&quot;quoted_tweet&quot;:{},&quot;reply_count&quot;:47,&quot;retweet_count&quot;:132,&quot;like_count&quot;:1149,&quot;impression_count&quot;:74215,&quot;expanded_url&quot;:null,&quot;video_url&quot;:&quot;https://video.twimg.com/amplify_video/2041197846888611840/vid/avc1/1088x720/e_TeuAl0d5aZ-EJr.mp4&quot;,&quot;belowTheFold&quot;:true}&quot;</a> data-component-name=&quot;Twitter2ToDOM&quot;&gt;</p><p>@swyx nerd-sniped me into building an Open-source Dropbox.\\n\\nHere is Locker: the ultimate open-source Google Drive/box/Dropbox alternative 💾\\n- Provider agnostic (S3, R2, vercel blob, local)\\n- BYOB (Bring your own bucket)\\n- Virtual file system\\n- QMD Search plugin &quot;,&quot;username&quot;:&quot;zachmeyer&quot;,&quot;name&quot;:&quot;Zach&quot;,&quot;profile_image_url&quot;:&quot;<a href="https://pbs.substack.com/profile_images/1901272779858874369/bWecuoh__normal.jpg%22,%22date%22:%222026-04-05T20:37:39.000Z%22,%22photos%22:%5B%7B%22img_url%22:%22https://pbs.substack.com/media/HFEVmeiawAAU_wS.jpg%22,%22link_url%22:%22https://t.co/tiy1sKN3Dd%22%7D%5D,%22quoted_tweet%22:%7B%7D,%22reply_count%22:30,%22retweet_count%22:42,%22like_count%22:858,%22impression_count%22:57812,%22expanded_url%22:null,%22video_url%22:null,%22belowTheFold%22:true%7D%22" target="_blank" rel="noreferrer">https://pbs.substack.com/profile_images/1901272779858874369/bWecuoh__normal.jpg&quot;,&quot;date&quot;:&quot;2026-04-05T20:37:39.000Z&quot;,&quot;photos&quot;:[{&quot;img_url&quot;:&quot;https://pbs.substack.com/media/HFEVmeiawAAU_wS.jpg&quot;,&quot;link_url&quot;:&quot;https://t.co/tiy1sKN3Dd&quot;}],&quot;quoted_tweet&quot;:{},&quot;reply_count&quot;:30,&quot;retweet_count&quot;:42,&quot;like_count&quot;:858,&quot;impression_count&quot;:57812,&quot;expanded_url&quot;:null,&quot;video_url&quot;:null,&quot;belowTheFold&quot;:true}&quot;</a> data-component-name=&quot;Twitter2ToDOM&quot;&gt;</p><p>Find me on <a href="https://x.com/bentossell/" target="_blank" rel="noreferrer">X</a>, <a href="https://www.linkedin.com/in/ben-tossell-70453537/" target="_blank" rel="noreferrer">Linkedin</a>, or <a href="https://www.youtube.com/@bentossell694" target="_blank" rel="noreferrer">YouTube</a></p><p>Read <a href="https://bensbites.substack.com/about" target="_blank" rel="noreferrer">about me</a> and Ben’s Bites</p><p>📷 thumbnail by <a href="https://www.x.com/keshavatearth" target="_blank" rel="noreferrer">@keshavatearth</a></p><ul><li>sponsors who make this newsletter possible 😃</li></ul><p>Wanna partner with us for the next quarter?</p><p>Email us at <a href="mailto:shanice@bensbites.com" target="_blank" rel="noreferrer">shanice@bensbites.com</a> or <a href="mailto:k@bensbites.com" target="_blank" rel="noreferrer">k@bensbites.com</a></p><hr>',48)])])}const d=t(n,[["render",s]]);export{m as __pageData,d as default};
